import pandas as pd

def statistical_analyzer(data: dict, numeric_fields: list[str] | None = None) -> dict:
    df = pd.DataFrame(data.get("data", []))
    if numeric_fields is None:
        numeric_fields = df.select_dtypes(include="number").columns.tolist()
    stats = {}
    for field in numeric_fields:
        if field not in df.columns:
            continue
        col = df[field].dropna()
        q1, q3 = col.quantile(0.25), col.quantile(0.75)
        iqr = q3 - q1
        outliers = col[(col < q1 - 1.5 * iqr) | (col > q3 + 1.5 * iqr)].tolist()
        stats[field] = {"mean": round(col.mean(), 4), "median": round(col.median(), 4), "std": round(col.std(), 4), "min": round(col.min(), 4), "max": round(col.max(), 4), "outlier_count": len(outliers)}
    return {"statistics": stats, "fields_analyzed": numeric_fields}
